import React from 'react';

const VideoCard = ({ title, description, videoUrl, w, h }) => {
  return (
    <div className="card">
      <div className="embed-responsive embed-responsive-16by9">
      <iframe width={w} height={h} src={videoUrl} title={title} frameborder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" referrerpolicy="strict-origin-when-cross-origin" allowfullscreen></iframe>
      </div>
      <div className="card-body">
        <h5 className="card-title">{title}</h5>
        <p className="card-text">{description}</p>
        <a href={videoUrl} className="btn btn-primary">Ver Video</a>
      </div>
      <iframe width={w} height={h} src={videoUrl} title={title} frameborder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" referrerpolicy="strict-origin-when-cross-origin" allowfullscreen></iframe>
    </div>
  );
};

export default VideoCard;
